parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "title": { "type": "string", "description": "The document title." },
    "doc_type": { "type": "string", "description": "The kind of document, e.g. guide, policy, spec, FAQ, release notes." },
    "summary": { "type": "string", "description": "A one or two sentence summary of what the document covers." },
    "topics": { "type": "array", "items": { "type": "string" }, "description": "The main subjects the document covers, as a list of short phrases." },
    "keywords": { "type": "array", "items": { "type": "string" }, "description": "Salient search keywords or terms, lowercase." },
    "entities": { "type": "array", "items": { "type": "string" }, "description": "Notable named things mentioned: products, models, people, organizations, versions, standards." },
    "effective_date": { "type": "string", "description": "A relevant date if present (published, effective, or revised), else empty." },
    "audience": { "type": "string", "description": "Who the document is written for, e.g. customers, engineers, internal ops." }
  }
}

parameters.jsCode:
// ── Meta tagging (customize with AI-SETUP-PROMPT.md) ───────────────────────
// Merges the LLM-extracted fields with the deterministic fields from Drive
// into one metadata object per document. To retarget this pipeline to a
// different documentation type, change the `extracted` mapping below so its
// keys match the fields you defined in the Information Extractor schema, and
// mirror those keys in the Default Data Loader node.
function contentHash(str) {
  // Fast non-crypto fingerprint (FNV-1a style, 64-bit hex). No 'crypto'
  // dependency, so it runs in both the built-in Code node and the external
  // task runner. Good enough for change-detection and dedup.
  let h1 = 0x811c9dc5;
  let h2 = (0x811c9dc5 ^ 0x5bd1e995) >>> 0;
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ c, 0x01000193);
    h2 = Math.imul(h2 ^ c, 0x01000193);
  }
  const hex = (n) => (n >>> 0).toString(16).padStart(8, '0');
  return hex(h1) + hex(h2);
}
const results = [];
const mdItems = $('MarkItDown Convert').all();
const trigItems = $('Google Drive Trigger').all();
for (let i = 0; i < items.length; i++) {
  const md = mdItems[i].json.markdown;
  const t = trigItems[i].json;
  const ex = items[i].json.output || {};
  const hash = contentHash(md || '');

  // Fields the LLM pulled out of the document body. Edit these to match your
  // Information Extractor schema.
  const extracted = {
    title: ex.title ?? null,
    doc_type: ex.doc_type ?? null,
    summary: ex.summary ?? null,
    topics: Array.isArray(ex.topics) ? ex.topics : [],
    keywords: Array.isArray(ex.keywords) ? ex.keywords : [],
    entities: Array.isArray(ex.entities) ? ex.entities : [],
    effective_date: ex.effective_date ?? null,
    audience: ex.audience ?? null,
  };

  // Deterministic fields from the source system. Usually leave as-is.
  const provenance = {
    file_id: t.id,
    file_name: t.name,
    source: 'google_drive',
    mime_type: t.mimeType,
    modified_time: t.modifiedTime,
    content_hash: hash,
    ingested_at: new Date().toISOString(),
  };

  results.push({ json: {
    markdown: md,
    metadata: { ...extracted, ...provenance },
  } });
}
return results;

// ── Structure-aware chunking ───────────────────────────────────────────────
// Chunks Markdown by heading so each chunk is a coherent section. Three tiers:
//   1. Real Markdown headings (#..######) when present -> true structure
//      (Word / Google Doc / HTML / Markdown keep their heading styles).
//   2. Heuristic heading recovery for flat text: most PDFs convert to plain
//      paragraphs with no '#', so short title-like lines become boundaries.
//   3. Clean, line-aware fixed-size windows as a last resort.
// Also strips converter noise (form feeds, page numbers, repeating page
// headers/footers). Each chunk carries its heading breadcrumb (section_path),
// prepended to the embedded text. Single source of truth for chunking; the
// recursive splitter downstream is a large pass-through.
const MAX_CHARS = 1500;   // section-size ceiling before sub-splitting
const OVERLAP_LINES = 2;  // whole trailing lines carried into the next chunk

const src = $('Assemble Metadata').first().json;
let md = src.markdown || '';
const meta = src.metadata || {};

// 1. Clean converter noise.
md = md.replace(/\f/g, '\n');
const rawLines = md.split('\n');
const freq = {};
for (const l of rawLines) {
  const t = l.trim();
  if (t && t.length <= 40) freq[t] = (freq[t] || 0) + 1;
}
const isNoise = (t) => {
  if (!t) return false;
  if (/^\d{1,4}$/.test(t)) return true;                        // lone page number
  if (/\d{1,2}:\d{2}\s*(AM|PM)?/i.test(t) && t.length <= 40) return true; // timestamp
  if ((freq[t] || 0) >= 3 && t.length <= 40) return true;      // repeating header/footer
  return false;
};
const lines = rawLines.filter((l) => !isNoise(l.trim()));

// 2. Detect headings.
const realHeadings = lines.filter((l) => /^#{1,6}\s+\S/.test(l)).length;
const isHeuristicHeading = (line) => {
  const t = line.trim();
  if (!t || t.length > 60) return false;
  if (/^[•\-*◦▪·]/.test(t)) return false;      // bullet / sub-bullet
  if (/^\d+[.)]\s/.test(t)) return false;       // enumerated list
  if (!/^[A-Z0-9#]/.test(t)) return false;      // titles start capitalized
  if (/[.,:;]$/.test(t)) return false;          // ends like prose
  if (t.split(/\s+/).length > 8) return false;  // too long to be a title
  if (!/[A-Za-z]/.test(t)) return false;
  return true;
};

const sections = [];
let stack = [];
let buf = [];
let curPath = '';
const pushSection = () => {
  const text = buf.join('\n').trim();
  if (text) sections.push({ path: curPath, text });
  buf = [];
};

if (realHeadings >= 2) {
  for (const line of lines) {
    const m = line.match(/^(#{1,6})\s+(.*)$/);
    if (m) {
      pushSection();
      const level = m[1].length;
      const title = m[2].trim();
      stack = stack.filter((s) => s.level < level);
      stack.push({ level, title });
      curPath = stack.map((s) => s.title).join(' > ');
      buf.push(line);
    } else {
      buf.push(line);
    }
  }
  pushSection();
} else {
  for (const line of lines) {
    if (isHeuristicHeading(line)) {
      pushSection();
      curPath = line.trim();
      buf.push(line);
    } else {
      buf.push(line);
    }
  }
  pushSection();
}
if (!sections.length && lines.join('\n').trim()) {
  sections.push({ path: '', text: lines.join('\n').trim() });
}

// 3. Line-aware sub-split of oversized sections.
const subSplit = (text) => {
  if (text.length <= MAX_CHARS) return [text];
  const ls = text.split('\n');
  const out = [];
  let cur = [];
  let len = 0;
  for (const l of ls) {
    if (len && len + l.length + 1 > MAX_CHARS) {
      out.push(cur.join('\n').trim());
      cur = cur.slice(-OVERLAP_LINES);
      len = cur.join('\n').length;
    }
    cur.push(l);
    len += l.length + 1;
  }
  if (cur.join('\n').trim()) out.push(cur.join('\n').trim());
  return out;
};

// 4. Emit one item per chunk.
const results = [];
let idx = 0;
for (const sec of sections) {
  for (const piece of subSplit(sec.text)) {
    const prefix = sec.path ? '[' + sec.path + ']\n\n' : '';
    results.push({ json: {
      text: prefix + piece,
      heading: sec.path ? sec.path.split(' > ').pop() : null,
      section_path: sec.path,
      chunk_index: idx++,
      ...meta,
    } });
  }
}
return results;
